import torch
import torch.nn as nn
import torch.nn.functional as F
from torch_geometric.nn import GATConv
import numpy as np

class TemporalEncoder(nn.Module):
    def __init__(self, input_dim, hidden_dim, num_layers=2):
        super().__init__()
        self.lstm = nn.LSTM(input_dim, hidden_dim, num_layers, batch_first=True)

    def forward(self, x):
        # x shape: (batch, seq_len, features)
        _, (h_n, _) = self.lstm(x)
        return h_n[-1]  # Return last layer hidden state

class TGATLayer(nn.Module):
    def __init__(self, in_channels, out_channels, heads=4, concat=True):
        super().__init__()
        self.gat = GATConv(in_channels, out_channels, heads=heads, concat=concat)

    def forward(self, x, edge_index):
        return self.gat(x, edge_index)

class MultiObjectiveOutput(nn.Module):
    def __init__(self, in_channels, metrics=['power', 'area', 'delay']):
        super().__init__()
        self.metrics = metrics
        self.layers = nn.ModuleList([
            nn.Linear(in_channels, 1) for _ in metrics
        ])

    def forward(self, x):
        return [layer(x).squeeze(-1) for layer in self.layers]

class TGAT(nn.Module):
    def __init__(self, node_features, temporal_dim, gat_hidden, gat_heads, 
                 output_metrics=['power', 'area', 'delay']):
        super().__init__()
        self.temporal_encoder = TemporalEncoder(node_features, temporal_dim)
        self.gat_layer = TGATLayer(temporal_dim, gat_hidden, gat_heads)
        self.output_layer = MultiObjectiveOutput(gat_hidden, output_metrics)

    def forward(self, node_features, edge_index, temporal_seq):
        # Encode temporal information
        temporal_repr = self.temporal_encoder(temporal_seq)
        # Apply GAT
        gat_output = self.gat_layer(temporal_repr, edge_index)
        # Multi-objective prediction
        outputs = self.output_layer(gat_output)
        return outputs

def multi_objective_loss(predictions, targets, weights=[1.0, 1.0, 1.0]):
    """Compute weighted sum of losses for multiple objectives"""
    losses = []
    for pred, target, weight in zip(predictions, targets, weights):
        loss = F.mse_loss(pred, target) * weight
        losses.append(loss)
    return sum(losses)
