char *extensions[6];
int num_extensions;
int move_flag = 0;
int copy_flag = 0;

// Check if path is within home directory
int is_in_home(const char *path) {
    return strncmp(path, home_dir, strlen(home_dir)) == 0;
}

// Check if file has excluded extension
int is_excluded(const char *filename) {
    const char *dot = strrchr(filename, '.');
    if (!dot) return 0;

    for (int i = 0; i < num_extensions; i++) {
        if (strcmp(dot + 1, extensions[i]) == 0) {
            return 1;
        }
    }
    return 0;
}

// Copy file function
int copy_file(const char *src, const char *dst) {
    FILE *src_f = fopen(src, "rb");
    FILE *dst_f = fopen(dst, "wb");

    if (!src_f || !dst_f) {
        perror("fopen");
        if (src_f) fclose(src_f);
        if (dst_f) fclose(dst_f);
        return -1;
    }

    char buffer[1024];
    size_t bytes;
    while ((bytes = fread(buffer, 1, sizeof(buffer), src_f)) > 0) {
        fwrite(buffer, 1, bytes, dst_f);
    }

    fclose(src_f);
    fclose(dst_f);
    return 0;
}

// Process each file/directory
int process_entry(const char *fpath, const struct stat *sb, int typeflag, struct FTW *ftwbuf) {
    // Skip root directory
    if (strcmp(fpath, source_dir) == 0) return 0;

    // Get relative path from source
    char rel_path[1024];
    snprintf(rel_path, sizeof(rel_path), "%s", fpath + strlen(source_dir));

    // Skip if excluded by extension
    if (typeflag == FTW_F && is_excluded(basename((char*)fpath))) {
        return 0;
    }

    // Create destination path
    char dest_path[1024];
    snprintf(dest_path, sizeof(dest_path), "%s%s", dest_dir, rel_path);

    switch (typeflag) {
        case FTW_D:
        case FTW_DNR:
            // Create directory
            if (mkdir(dest_path, sb->st_mode) == -1 && errno != EEXIST) {
                perror("mkdir");
                return -1;
            }
            break;

        case FTW_F:
            // Copy/move file
            if (copy_flag) {
                if (copy_file(fpath, dest_path) != 0) {
                    return -1;
                }
            } else if (move_flag) {
                if (rename(fpath, dest_path) != 0) {
                    perror("rename");
                    return -1;
                }
            }
            break;
    }

    return 0;
}

int main(int argc, char *argv[]) {
    // Parse arguments
    if (argc < 4) {
        fprintf(stderr, "Usage: %s [-cp|-mv] source_dir destination_dir [extension1 extension2 ...]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    // Set flags
    if (strcmp(argv[1], "-cp") == 0) {
        copy_flag = 1;
    } else if (strcmp(argv[1], "-mv") == 0) {
        move_flag = 1;
    } else {
        fprintf(stderr, "Invalid option. Use -cp for copy or -mv for move.\n");
        exit(EXIT_FAILURE);
    }

    source_dir = argv[2];
    dest_dir = argv[3];

    // Get home directory
    home_dir = getenv("HOME");
    if (!home_dir) {
        fprintf(stderr, "Error: HOME environment variable not set\n");
        exit(EXIT_FAILURE);
    }

    // Validate paths are in home directory
    if (!is_in_home(source_dir)) {
        fprintf(stderr, "Error: Source directory must be within home directory\n");
        exit(EXIT_FAILURE);
    }

    if (!is_in_home(dest_dir)) {
        fprintf(stderr, "Error: Destination directory must be within home directory\n");
        exit(EXIT_FAILURE);
    }

    // Parse extensions
    num_extensions = 0;
    for (int i = 4; i < argc && num_extensions < 6; i++) {
        extensions[num_extensions++] = argv[i];
    }

    // Create destination directory if it doesn't exist
