    if (stat(dest_dir, &st) == -1) {
        if (mkdir(dest_dir, 0755) == -1) {
            perror("mkdir");
            exit(EXIT_FAILURE);
        }
    }

    // Traverse and process directory tree
    if (nftw(source_dir, process_entry, 20, FTW_PHYS) == -1) {
        perror("nftw");
        exit(EXIT_FAILURE);
    }

    return 0;
}
