% H2 State Feedback Controller Design using YALMIP LMIs
% System matrices
% A, B, C are given state-space matrices

% Define decision variables
n = size(A,1); m = size(B,2); p = size(C,1);
X = sdpvar(n,n,'symmetric');
Q = sdpvar(p+m,p+m,'symmetric');
Y = sdpvar(n,p+m);

% Disturbance to output matrix D
D = [zeros(p,m); -eye(m)];

% LMI constraints
constraints = [
    A*X + X*A' - B*Y - Y'*B' + B*B' < 0;
    [X, (C*X + D*Y)'; (C*X + D*Y), Q] >= 0;
    X >= 0;
];

% Objective: minimize trace(Q)
objective = trace(Q);

% Solve optimization problem
optimize(constraints, objective);

% Extract solution
Xsol = double(X);
Ysol = double(Y);
Qsol = double(Q);

% Compute controller gain
K = Ysol * inv(Xsol);

% Compare with LQR (for reference)
% LQR assumes Q = I, R = I for simplicity
Q_lqr = eye(n);
R_lqr = eye(m);
K_lqr = -inv(B'*Q_lqr*B + R_lqr)*(B'*Q_lqr*A);

