class Solution {
public:
    std::vector<int> maxFreqSubarray(std::vector<int>& nums1, std::vector<int>& nums2) {
        // Count frequencies in first array
        std::unordered_map<int, int> freq1;
        for (int num : nums1) {
            freq1[num]++;
        }

        // Sliding window approach
        std::unordered_map<int, int> freq2;
        int left = 0, maxLen = 0;
        std::vector<int> result;

        for (int right = 0; right < nums2.size(); right++) {
            // Add current element to window
            freq2[nums2[right]]++;

            // Shrink window if constraint violated
            while (freq2[nums2[right]] > freq1[nums2[right]]) {
                freq2[nums2[left]]--;
                left++;
            }

            // Update result if we found a longer valid subarray
            if (right - left + 1 > maxLen) {
                maxLen = right - left + 1;
                result = std::vector<int>(nums2.begin() + left, nums2.begin() + right + 1);
            }
        }

        return result;
    }
