    V: AsRef<[u8]> + Clone,
{
    pub fn new(tree_size: usize, stash_size: usize) -> Self {
        let mut tree = Vec::with_capacity(tree_size);
        for i in 0..tree_size {
            tree.push(ORAMNode::empty());
