        let mut result = None;
        for i in 0..self.tree_size {
            if self.tree[i].position == position && !self.tree[i].is_empty {
                result = Some(self.tree[i].value.clone());
                break;
            }
        }

        // Oblivious stash update
        self.stash_update(key_bytes, result.clone());

        result
    }

    pub fn write(&mut self, key: K, value: V) {
        let key_bytes = key.as_ref().to_vec();
        let value_bytes = value.as_ref().to_vec();

        let position = if let Some(pos) = self.position_map.get(&key_bytes) {
            *pos
        } else {
            self.position_map.len()
        };

        // Oblivious insertion
        let node = ORAMNode::new(position, key_bytes.clone(), value_bytes);
        self.tree[position % self.tree_size] = node;
        self.position_map.insert(key_bytes, position);

        // Oblivious stash update
        self.stash_update(key_bytes, None);
    }

    fn stash_update(&mut self, key: Vec<u8>, value: Option<Vec<u8>>) {
        if self.stash.len() >= self.stash_size {
            self.stash.remove(0);
        }
        self.stash.push(ORAMNode::new(0, key, value.unwrap_or_default()));
    }
}
