                        old_size = len(self.first_sets[nt])
                        self.first_sets[nt].update(self.first_sets[first_symbol] - {'epsilon'})
                        if 'epsilon' in self.first_sets[first_symbol]:
                            # Continue checking remaining symbols
                            i = 1
                            while i < len(prod) and 'epsilon' in self.first_sets[prod[i-1]]:
                                if prod[i] in self.terminals:
                                    self.first_sets[nt].add(prod[i])
                                    break
                                else:
                                    self.first_sets[nt].update(self.first_sets[prod[i]] - {'epsilon'})
                                    i += 1
                            if i == len(prod) and 'epsilon' in self.first_sets[prod[-1]]:
                                self.first_sets[nt].add('epsilon')
                        if len(self.first_sets[nt]) > old_size:
                            changed = True

    def compute_follow(self):
        """Compute FOLLOW sets for all non-terminals"""
        self.follow_sets = {nt: set() for nt in self.non_terminals}
        self.follow_sets['E'].add('$')  # End marker

        changed = True
        while changed:
            changed = False
            for nt, productions in self.rules.items():
                for prod in productions:
                    for i, symbol in enumerate(prod):
                        if symbol in self.non_terminals:
                            # Get FOLLOW of symbol
                            follow_set = set()
                            if i + 1 < len(prod):
                                # Add FIRST of next symbol
                                next_symbol = prod[i+1]
                                if next_symbol in self.terminals:
                                    follow_set.add(next_symbol)
                                else:
                                    follow_set.update(self.first_sets[next_symbol])
                                    if 'epsilon' in self.first_sets[next_symbol]:
                                        # Add FOLLOW of current non-terminal
                                        follow_set.update(self.follow_sets[nt] - {'epsilon'})
                            else:
                                # Add FOLLOW of current non-terminal
                                follow_set.update(self.follow_sets[nt])

                            # Update FOLLOW set
                            old_size = len(self.follow_sets[symbol])
                            self.follow_sets[symbol].update(follow_set)
                            if len(self.follow_sets[symbol]) > old_size:
                                changed = True

    def build_predict_table(self):
        """Build LL(1) prediction table"""
        self.predict_table = {}
        for nt, productions in self.rules.items():
            self.predict_table[nt] = {}
            for prod in productions:
                if prod == ['epsilon']:
                    for terminal in self.follow_sets[nt]:
                        if terminal != 'epsilon':
                            if terminal not in self.predict_table[nt]:
                                self.predict_table[nt][terminal] = prod
                else:
                    first_set = set()
                    i = 0
                    while i < len(prod):
                        if prod[i] in self.terminals:
                            first_set.add(prod[i])
                            break
                        else:
                            first_set.update(self.first_sets[prod[i]] - {'epsilon'})
                            if 'epsilon' not in self.first_sets[prod[i]]:
                                break
                        i += 1

                    if i == len(prod) and 'epsilon' in self.first_sets[prod[-1]]:
                        first_set.add('epsilon')

                    for terminal in first_set:
                        if terminal != 'epsilon':
                            if terminal not in self.predict_table[nt]:
                                self.predict_table[nt][terminal] = prod

    def print_sets(self):
        """Print FIRST and FOLLOW sets"""
        print("FIRST SETS:")
        for nt, first in sorted(self.first_sets.items()):
            print(f"FIRST({nt}) = {{{', '.join(sorted(first))}}}")

        print("\nFOLLOW SETS:")
        for nt, follow in sorted(self.follow_sets.items()):
            print(f"FOLLOW({nt}) = {{{', '.join(sorted(follow))}}}")

    def print_predict_table(self):
        """Print prediction table"""
        terminals_list = sorted([t for t in self.terminals if t != 'epsilon'])
        print("\nLL(1) PREDICTION TABLE:")
        header = "Non-Terminal"
        for term in terminals_list:
            header += f"\t{term}"
        print(header)

        for nt in sorted(self.non_terminals):
            row = nt
            for term in terminals_list:
                if term in self.predict_table.get(nt, {}):
                    prod_str = ' '.join(self.predict_table[nt][term])
                    row += f"\t{prod_str}"
                else:
                    row += "\t"
            print(row)

    def parse(self, input_tokens):
        """Parse input tokens using LL(1) parsing"""
        stack = ['$', 'E']
        input_tokens.append('$')
        i = 0

        print("\nParsing trace:")
        print("Stack\t\tInput\t\tAction")
        print("-" * 50)

        while stack and i < len(input_tokens):
            top = stack.pop()
            current_token = input_tokens[i]

            if top == current_token:
                i += 1
                print(f"{stack}\t\t{input_tokens[i:]}\t\tMatched {top}")
            elif top in self.non_terminals:
                if current_token in self.predict_table[top]:
                    production = self.predict_table[top][current_token]
                    print(f"{stack}\t\t{input_tokens[i:]}\t\tApply {top} -> {' '.join(production)}")
                    if production != ['epsilon']:
                        # Push production in reverse order
                        for symbol in reversed(production):
                            if symbol != 'epsilon':
                                stack.append(symbol)
                else:
                    print(f"Error: No production found for {top} with input {current_token}")
                    return False
            else:
                print(f"Error: Unexpected token {current_token}")
                return False

        if i == len(input_tokens) and not stack:
            print("Parsing successful!")
            return True
        else:
            print("Parsing failed!")
            return False

# Example usage
def main():
    parser = LL1Parser()

    # Compute sets
    parser.compute_first()
    parser.compute_follow()
    parser.build_predict_table()

    # Display results
    parser.print_sets()
    parser.print_predict_table()

    # Test parsing
    test_input = ['id', '=', 'id', '+', 'num', ';']
    print(f"\nTesting input: {' '.join(test_input)}")
    parser.parse(test_input)

if __name__ == "__main__":
    main()
