// Main class
public class BountyPlugin extends JavaPlugin {
    private static BountyPlugin instance;
    private Economy economy;
    private Set<String> allowedWorlds;

    @Override
    public void onEnable() {
        instance = this;
        saveDefaultConfig();
        setupEconomy();
        loadAllowedWorlds();
        getCommand("bounty").setExecutor(new BountyCommand());
        getServer().getPluginManager().registerEvents(new DeathListener(), this);
    }

    private void setupEconomy() {
        if (getServer().getPluginManager().isPluginEnabled("Vault")) {
            RegisteredServiceProvider<Economy> rsp = getServer().getServicesManager().getRegistration(Economy.class);
            if (rsp != null) economy = rsp.getProvider();
        }
    }

    private void loadAllowedWorlds() {
        allowedWorlds = new HashSet<>(getConfig().getStringList("allowed-worlds"));
    }

    public static BountyPlugin getInstance() { return instance; }
    public Economy getEconomy() { return economy; }
    public Set<String> getAllowedWorlds() { return allowedWorlds; }
}

// Command executor
class BountyCommand implements CommandExecutor {
    @Override
    public boolean onCommand(CommandSender sender, Command cmd, String label, String[] args) {
        if (args.length == 0) return false;

        Player player = (Player) sender;
        if (!BountyPlugin.getInstance().getAllowedWorlds().contains(player.getWorld().getName())) {
            player.sendMessage("§cBounties not allowed in this world");
            return true;
        }

        switch (args[0].toLowerCase()) {
            case "add":
                if (args.length < 3) return false;
                return addBounty(player, args[1], args[2]);
            default:
                return showBounty(player, args[0]);
        }
    }

    private boolean showBounty(Player player, String targetName) {
        double bounty = BountySystem.getBounty(targetName);
        player.sendMessage("§6Bounty on §e" + targetName + "§6: §a$" + bounty);
        return true;
    }

    private boolean addBounty(Player player, String targetName, String amountStr) {
        Economy econ = BountyPlugin.getInstance().getEconomy();
        if (econ == null) {
            player.sendMessage("§cVault not found");
            return true;
        }

        double amount;
        try { amount = Double.parseDouble(amountStr); }
        catch (NumberFormatException e) { return false; }

        if (amount <= 0) {
            player.sendMessage("§cAmount must be positive");
            return true;
        }

        if (econ.getBalance(player) < amount) {
            player.sendMessage("§cNot enough money");
            return true;
        }

        econ.withdrawPlayer(player, amount);
        BountySystem.addBounty(targetName, amount);
        player.sendMessage("§aAdded §6$" + amount + " §ato bounty on §e" + targetName);
        return true;
    }
}

// Death listener
class DeathListener implements Listener {
    @EventHandler
    public void onPlayerDeath(PlayerDeathEvent event) {
        Player victim = event.getEntity();
        Player killer = victim.getKiller();

        if (killer == null) return;
        if (!BountyPlugin.getInstance().getAllowedWorlds().contains(victim.getWorld().getName())) return;

        double bounty = BountySystem.getBounty(victim.getName());
        if (bounty <= 0) return;

        Economy econ = BountyPlugin.getInstance().getEconomy();
        if (econ != null) {
            econ.depositPlayer(killer, bounty);
            killer.sendMessage("§aYou received §6$" + bounty + " §afrom killing §e" + victim.getName());
        }

        BountySystem.resetBounty(victim.getName());
    }
}

// Bounty system utility
class BountySystem {
    private static final Map<String, Double> bounties = new HashMap<>();

    public static double getBounty(String player) {
        return bounties.getOrDefault(player.toLowerCase(), 0.0);
    }

    public static void addBounty(String player, double amount) {
        bounties.put(player.toLowerCase(), bounties.getOrDefault(player.toLowerCase(), 0.0) + amount);
    }

    public static void resetBounty(String player) {
        bounties.remove(player.toLowerCase());
    }
}
