#!/usr/bin/env python3
import os
import sys
import logging
import pandas as pd
from pathlib import Path
import tabula

# Setup logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

def extract_pdf_data(pdf_path):
    """Extract data from a PDF file"""
    try:
        # Extract tables from first two pages
        tables = tabula.read_pdf(pdf_path, pages='1-2', multiple_tables=True)

        # Combine all tables into one DataFrame
        if tables:
            df = pd.concat(tables, ignore_index=True)
            df['source_file'] = os.path.basename(pdf_path)
            return df
        else:
            logger.warning(f"No tables found in {pdf_path}")
            return pd.DataFrame()

    except Exception as e:
        logger.error(f"Error processing {pdf_path}: {str(e)}")
        return pd.DataFrame()

def process_pdfs(folder_path):
    """Process all PDFs in a folder and combine into single DataFrame"""
    all_dataframes = []

    # Get all PDF files in folder
    pdf_files = list(Path(folder_path).glob("*.pdf"))

    if not pdf_files:
        logger.warning(f"No PDF files found in {folder_path}")
        return pd.DataFrame()

    logger.info(f"Found {len(pdf_files)} PDF files")

    # Process each PDF
    for pdf_file in pdf_files:
        logger.info(f"Processing {pdf_file.name}")
        df = extract_pdf_data(pdf_file)
        if not df.empty:
            all_dataframes.append(df)

    # Combine all DataFrames
    if all_dataframes:
        combined_df = pd.concat(all_dataframes, ignore_index=True)
        return combined_df
    else:
        logger.warning("No valid data extracted from any PDF")
        return pd.DataFrame()

def sort_and_save_dataframe(df, output_path):
    """Sort DataFrame by date and save to CSV"""
    try:
        # Try to identify date column
        date_columns = ['Posted Date', 'Date', 'posted_date', 'date']
        date_col = None

        for col in date_columns:
            if col in df.columns:
                date_col = col
                break

        if date_col:
            # Convert date column to datetime
            df[date_col] = pd.to_datetime(df[date_col], errors='coerce')
            # Sort by date (oldest to newest)
            df = df.sort_values(by=date_col)
            logger.info(f"Sorted data by {date_col}")
        else:
            logger.warning("No date column found for sorting")

        # Save to CSV
        df.to_csv(output_path, index=False)
        logger.info(f"Data saved to {output_path}")

    except Exception as e:
        logger.error(f"Error saving CSV: {str(e)}")

def main():
    if len(sys.argv) != 3:
        logger.error("Usage: python script.py <input_folder> <output_csv>")
        sys.exit(1)

    input_folder = sys.argv[1]
    output_csv = sys.argv[2]

    # Validate input folder
    if not os.path.isdir(input_folder):
        logger.error(f"Input folder does not exist: {input_folder}")
        sys.exit(1)

    logger.info("Starting PDF processing...")

    # Process PDFs and get combined DataFrame
    df = process_pdfs(input_folder)

    if not df.empty:
        logger.info(f"Combined {len(df)} rows of data")
        sort_and_save_dataframe(df, output_csv)
    else:
        logger.warning("No data to save")

if __name__ == "__main__":
    main()
