import re

def parse_profile_data(html_content):
    soup = BeautifulSoup(html_content, 'html.parser')
    result = {}

    # Extract all dt/dd pairs
    dt_elements = soup.find_all('dt')
    dd_elements = soup.find_all('dd')

    # Create mapping from dt text to dd text
    dt_dd_map = {}
    for dt, dd in zip(dt_elements, dd_elements):
        key = dt.get_text().strip()
        value = dd.get_text().strip()
        dt_dd_map[key] = value

    # Map keys to result
    key_mapping = {
        'Username': 'Username',
        'Title': 'Title',
        'Real name': 'Real name',
        'Last post': 'Last post',
        'Registered': 'Registered'
    }

    for key, target_key in key_mapping.items():
        if key in dt_dd_map:
            result[target_key] = dt_dd_map[key]

    # Handle 'Invited by' specially
    if 'Invited by' in dt_dd_map:
        invited_by_html = soup.find('dt', string='Invited by').find_next_sibling('dd')
        if invited_by_html:
            link = invited_by_html.find('a')
            if link:
                href = link.get('href', '')
                uid_match = re.search(r'id=(\d+)', href)
                result['Invited by UID'] = uid_match.group(1) if uid_match else ''
                result['Invited by'] = link.get_text().strip()

    return result
